 1	import type { FC } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  EmptyState,
 7	  EmptyStateActions,
 8	  EmptyStateBody,
 9	  EmptyStateHeader,
10	  EmptyStateIcon,
11	  Flex,
12	  FlexItem,
13	} from '@patternfly/react-core';
14	import { ExclamationCircleIcon } from '@patternfly/react-icons';
15	import * as PatternflyTokens from '@patternfly/react-tokens';
16	import { useForkliftTranslation } from '@utils/i18n';
17	
18	type ReviewStepErrorStateProps = {
19	  error: string;
20	  onBackToReviewClick: () => void;
21	};
22	
23	const ReviewStepErrorState: FC<ReviewStepErrorStateProps> = ({ error, onBackToReviewClick }) => {
24	  const { t } = useForkliftTranslation();
25	
26	  return (
27	    <EmptyState className="pf-v6-u-h-100">
28	      <EmptyStateHeader
29	        titleText={t('Failed to create plan')}
30	        headingLevel="h4"
31	        icon={
32	          <EmptyStateIcon
33	            icon={ExclamationCircleIcon}
34	            color={PatternflyTokens.global_danger_color_100.var}
35	          />
36	        }
37	      />
38	      <EmptyStateBody>
39	        <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsLg' }}>
40	          <FlexItem>{error}</FlexItem>
41	
42	          <EmptyStateActions>
43	            <Button variant={ButtonVariant.primary} onClick={onBackToReviewClick}>
44	              {t('Go back to review step')}
45	            </Button>
46	          </EmptyStateActions>
47	        </Flex>
48	      </EmptyStateBody>
49	    </EmptyState>
50	  );
51	};
52	
53	export default ReviewStepErrorState;

